    return _mask&keeperTypeBGAudio;
}

- (BOOL)bgLocation {
    return _mask&keeperTypeBGLocation;
}


#pragma mark background keeper methods

- (void)startBGAudio {
    // Set up audio session once.
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });

    if (_avAudioPlayer == nil) {
        _avAudioPlayer = OBJC_INSTANCE_OF_CLASS("AVAudioPlayer");
        OBJC_MSGSEND_VOID_ID_ID(_avAudioPlayer, "initWithContentsOfURL:error:", _audioURL, nil);
        OBJC_MSGSEND_VOID_NSINTEGER(_avAudioPlayer, "setNumberOfLoops:", -1);
        OBJC_MSGSEND_VOID(_avAudioPlayer, "prepareToPlay");
        OBJC_MSGSEND_VOID(_avAudioPlayer, "play");
        NSLog(@"BG:start play.");
        // register for audio interruption notification
        [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onRecieveBGAudioInterruptionNotification:) name:AVAudioSessionInterruptionNotification object:nil];
    }
}

- (void)stopBGAudio {
    if (_avAudioPlayer) {
        OBJC_MSGSEND_VOID(_avAudioPlayer, "stop");
        NSLog(@"BG:stop play.");
        _avAudioPlayer = nil;
        [[NSNotificationCenter defaultCenter] removeObserver:self name:AVAudioSessionInterruptionNotification  object:nil];
    }
}

- (void)onRecieveBGAudioInterruptionNotification:(NSNotification *)notification {
    NSDictionary *userInfo = notification.userInfo;
    NSNumber *interruptionType = userInfo[AVAudioSessionInterruptionTypeKey];
    if ([interruptionType isEqualToNumber:[NSNumber numberWithInt:AVAudioSessionInterruptionTypeBegan]]) {
        if ([_avAudioPlayer isPlaying]) {
            OBJC_MSGSEND_VOID(_avAudioPlayer, "pause");
        }
    } else if ([interruptionType isEqualToNumber:[NSNumber numberWithInt:AVAudioSessionInterruptionTypeEnded]]) {
        NSNumber *option = userInfo[AVAudioSessionInterruptionOptionKey];
        if ([option isEqualToNumber:[NSNumber numberWithInt:AVAudioSessionInterruptionOptionShouldResume]]) {
            OBJC_MSGSEND_VOID(_avAudioPlayer, "play");
        }
    } else {
        NSParameterAssert(false);
    }
}

#pragma mark app lifecycle events

- (void)onAppEnterBackground {
    if ([self bgAudio] && ([WBVAppDownloadManager.sharedManager isDownloading] || [WBVAppResDownloadManager.sharedManager isDownloading])) {
        [self startBGAudio];
        return;
    }
    if([self bgAudio] &&([[NSUserDefaults standardUserDefaults] objectForKey:@"LISTEN_START"]||[[NSUserDefaults standardUserDefaults] objectForKey:@"RECEIVEING"]))
    {
        [self startBGAudio];
        return;
    }
    WBVAppModel *runningVApp = WBVAppManager.sharedManager.runningVApp;
    if ([self bgAudio] && vapp_is_running() && runningVApp){
        // use local logic bgmode's set
        if (runningVApp.userInfo.backgroundMode) {
            [self startBGAudio];
        }
    }
}

- (void)onAppEnterForeground {
    [self stopBGAudio];
}

- (void)onAppWillTerminate {
    NSLog(@"BG:terminating.");
    WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;
    if (runningVApp != nil && runningVApp.userInfo.observeTerminate) {
        UNMutableNotificationContent *content = [[UNMutableNotificationContent alloc] init];
        content.title = @"温馨提示";
        content.body = @"微盒将要退出";
        content.sound = [UNNotificationSound defaultSound];
        UNTimeIntervalNotificationTrigger *trigger = [UNTimeIntervalNotificationTrigger triggerWithTimeInterval:0.1 repeats:NO];
        UNNotificationRequest *request = [UNNotificationRequest requestWithIdentifier:@"con.xinzhu.webox.usernotificaiton.terminate" content:content trigger:trigger];
        [[UNUserNotificationCenter currentNotificationCenter] addNotificationRequest:request withCompletionHandler:nil];
    }
}



@end

