    //     self.vappUsedTimeInSecond = 0;
    //     self.appUsedTimeInSecond = 0;
    // });
    uint32_t appSeconds = [self wholeSecondsFromDuration:self.appUsedTimeInSecond];
    uint32_t vappSeconds = [self wholeSecondsFromDuration:self.vappUsedTimeInSecond];
    uint32_t backgroundSeconds = [self wholeSecondsFromDuration:self.backgroundUsedTimeInSecond];
    if (appSeconds == 0 && vappSeconds == 0) {
        [self persistUsageState];
        return;
    }
    NSMutableDictionary *dataDict = [@{
        @"v" : @(vappSeconds),
        @"a" : @(appSeconds)
    } mutableCopy];
    if (backgroundSeconds > 0) {
        dataDict[kEventBackgroundDurationParamKey] = @(backgroundSeconds);
    }
    // 只有当一轮累计明确只属于同一个 vapp 时，才携带 i，避免把 v 归错到其他 app。
    if (self.pendingVappId > 0) {
        dataDict[@"i"] = @(self.pendingVappId);
    }
    [WBEventManager addEventWithType:eventTypeAppHeartBeat data:dataDict];
    self.vappUsedTimeInSecond = 0;
    self.appUsedTimeInSecond = 0;
    self.backgroundUsedTimeInSecond = 0;
    self.pendingVappId = 0;
    self.lastUsageRecordTime = CFAbsoluteTimeGetCurrent();
    [self persistUsageState];

    // do event action request
    dispatch_async(dispatch_get_main_queue(), ^{
        if (WBAppManager.sharedManager.isActive) {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInForeground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInForeground defaultHandler:nil];
            }
        } else {
            if (vapp_is_running()) {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappRunningInBackground defaultHandler:nil];
            } else {
                [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppRunningInBackground defaultHandler:nil];
            }
        }
    });
}

- (void)processEventList {
    if (CFAbsoluteTimeGetCurrent()-_lastReportTime >= self.reportInterval) {
        [self doProcessEventList];
    }

    // process the queue every 1 sec
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1 * NSEC_PER_SEC)), [self queue], ^{
        [self processEventList];
    });
}

- (void)doProcessEventList {
    if (_enabled == FALSE) {
        return;
    }
    NSMutableArray *toBeReport = [[NSMutableArray alloc] init];
    for (WBEvent *event in _eventList) {
        if (event.status == eventStatusAwaitReport) {
            event.status = eventStatusReporting;
            [toBeReport addObject:event];
        }
    }

    if ([toBeReport count] > 0) {
        NSMutableString *jsonObj= [[NSMutableString alloc] initWithString: @"["];
        for (WBEvent *event in toBeReport) {
            if ([toBeReport indexOfObject:event] != 0) {
                [jsonObj appendString:@","];
            }
            if (event.params) {
                [jsonObj appendFormat:@"{\"t\":%@,\"n\":%@,\"d\":%@}", @(event.time),@(event.type), [event.params modelToJSONString]];
            } else {
                [jsonObj appendFormat:@"{\"t\":%@,\"n\":%@}", @(event.time),@(event.type)];
            }
        }
        [jsonObj appendString:@"]"];
        [[WBNetworkManager defaultManager] reportEventsSync:@(eventTypeMergedEvents) withData:jsonObj time:@(CFAbsoluteTimeGetCurrent()) callback:^(id  _Nullable json, NSError * _Nullable error) {
            if (error == nil) {
                [WBSettingManager.sharedManager syncWithHeatBeatResponse:[WBHeartBeatHttpModel modelWithJSON:json]];
                [self.eventList removeObjectsInArray:toBeReport];
            } else {
                if ([error.domain isEqual:WBNetworkRequestErrorDomain]) {
                    if (error.code == 503) {
                        WBSettingManager.sharedManager.LogRate = 0;
                        WBSettingManager.sharedManager.HeartBeatRate = 0;
                    }
                }
                for (WBEvent *event in toBeReport) {
                    event.status = eventStatusAwaitReport;  // reset to await report status
                }
            }
        }];
        self.lastReportTime = CFAbsoluteTimeGetCurrent();
    }
}

- (void)reportUrgentEvent:(WBEvent*)event {
    NSMutableString *jsonObj= [[NSMutableString alloc] initWithString: @"["];
    if (event.params) {
        [jsonObj appendFormat:@"{\"t\":%@,\"n\":%@,\"d\":%@}", @(event.time),@(event.type), [event.params modelToJSONString]];
    } else {
        [jsonObj appendFormat:@"{\"t\":%@,\"n\":%@}", @(event.time),@(event.type)];
    }
    [jsonObj appendString:@"]"];
    [[WBNetworkManager defaultManager] reportEventsSync:@(eventTypeUrgentEvents) withData:jsonObj time:@(CFAbsoluteTimeGetCurrent()) callback:^(id  _Nullable json, NSError * _Nullable error) {
        if (error) {
            NSLog(@"Urgent event report error: %@", error.localizedDescription);
        }
    }];
}

- (void)addEvent:(WBEvent*)event {
    NSLog(@"AddEvent:%d urgent:%d", (int)event.type, event.isUrgent);
    if (event.type == eventTypeAppHeartBeat) {
        [WBOperationTraceRecorder appendAction:@"heartbeat_enqueued"
                                 usageSnapshot:[self operationTraceUsageSnapshotInternal]
                                   extraFields:@{
                                       @"eventType": @(event.type),
                                       @"urgent": @(event.isUrgent),
                                       @"payload": event.params ?: @{}
                                   }];
    }
    if (event.isUrgent) {
        [self reportUrgentEvent:event];
    } else {
        dispatch_block_t enqueueBlock = ^{
            [[self eventList] addObject:event];
        };
        if (dispatch_get_specific(kWBEventManagerQueueSpecificKey)) {
            enqueueBlock();
        } else {
            dispatch_async(_queue, enqueueBlock);
        }
        //        dispatch_async(_queue, ^{
        //            [[self eventList] addObject:event];
        //        });
    }
}

