+ (NSDictionary<NSString *,NSNumber *> *)currentOperationTraceUsageSnapshot {
    WBEventManager *manager = [WBEventManager defaultManager];
    __block NSDictionary<NSString *, NSNumber *> *snapshot = nil;
    dispatch_block_t snapshotBlock = ^{
        snapshot = [manager operationTraceUsageSnapshotInternal];
    };
    if (dispatch_get_specific(kWBEventManagerQueueSpecificKey)) {
        snapshotBlock();
    } else {
        dispatch_sync(manager.queue, snapshotBlock);
    }
    return snapshot ?: @{
        @"appUsedTimeInSecond": @(0),
        @"vappUsedTimeInSecond": @(0),
        @"backgroundUsedTimeInSecond": @(0),
    };
}

/// 热启动回前台时，先补算后台挂起区间，再判断是否需要立刻发 heartbeat。
+ (void)syncUsageOnAppEnterForeground {
    WBEventManager *manager = [WBEventManager defaultManager];
    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    dispatch_sync(manager.queue, ^{
        // 先把后台挂起区间补算回来，再决定是否已经达到 heartbeat 阈值。
        [manager applyBackgroundUsageAtTime:now];
        [manager persistUsageState];
        [WBOperationTraceRecorder appendAction:@"app_enter_foreground"
                                 usageSnapshot:[manager operationTraceUsageSnapshotInternal]
                                   extraFields:nil];
        [manager reportHeartbeatIfNeeded];
    });
}

/// 维持原有的前台事件埋点，后台补时不再挂在 n=15 上。
+ (void)onAppEnterForeground {
