    });
}

/// 进入后台时先结算前台区间，再记录后台时间快照，供后续热启动或终止时补算。
+ (void)onAppEnterBackground {
    WBEventManager *manager = [WBEventManager defaultManager];
    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    NSInteger currentVappId = [manager currentRunningVappId];
    dispatch_sync(manager.queue, ^{
        // 先落掉进入后台前的前台时长，再保存后台快照，后续按时间差补算。
        [manager accumulateElapsedUsageAtTime:now];
        [manager persistUsageState];
        [WBOperationTraceRecorder appendAction:@"app_enter_background"
                                 usageSnapshot:[manager operationTraceUsageSnapshotInternal]
                                   extraFields:nil];
        [WBEventManager saveBackgroundTrackingAtTime:now runningVapp:(currentVappId > 0) vappId:currentVappId];
    });
    // 旧逻辑：
    // [WBEventManager addEventWithType:eventTypeAppEnterBackground];
    // [[WBEventManager defaultManager] saveAsync];
    [WBEventManager addEventWithType:eventTypeAppEnterBackground];
    [manager saveAsync];
    dispatch_async(dispatch_get_main_queue(), ^{
        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppEnterBackground defaultHandler:nil];
    });
}

/// 进程结束前保存最后一个可观测区间，让下一次冷启动还能继续累计同一轮 heartbeat。
+ (void)onAppWillTerminate {
    WBEventManager *manager = [WBEventManager defaultManager];
    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
    dispatch_sync(manager.queue, ^{
        // 保存进程结束前最后一段可观测时长，保证下次冷启动还能续上这轮 heartbeat。
        if ([WBEventManager hasBackgroundEnterTime]) {
            [manager applyBackgroundUsageAtTime:now];
        } else {
            [manager accumulateElapsedUsageAtTime:now];
        }
        [manager persistUsageState];
        [WBOperationTraceRecorder appendAction:@"app_will_terminate_event"
                                 usageSnapshot:[manager operationTraceUsageSnapshotInternal]
                                   extraFields:nil];
    });
    // 旧逻辑：
    // [[WBEventManager defaultManager] save];
    [manager save];
}


