#import "WBLinkActionModel.h"

@implementation WBNetworkManager (ActionRequest)

- (void)requestActionRequestInterfaceWithURI:(NSString *)uri method:(NSString *)method params:(NSDictionary *)params callback:(WBActionRequestCallback)callback {
    [[WBNetworkManager defaultManager] request:uri HTTPMethod:method params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        NSParameterAssert((error == nil) ^ (json == nil));
        if (error) {
            if (callback) callback(nil, error);
            return;
        }
        WBBaseActionModel *actionModel = [[WBDefaultActionFactory sharedFactory] buildActionWithDict:json sourceInterface:uri];
        callback(actionModel, nil);
    } isJsonContentType:NO];
}

- (void)requestActionRequestInterfaceWithURI:(NSString *)uri params:(NSDictionary *)params callback:(WBActionRequestCallback)callback {
    [self requestActionRequestInterfaceWithURI:uri method:@"POST" params:params callback:callback];
}

- (void)requestActionRequestInterfaceWithURI:(NSString *)uri vappId:(NSInteger)vappId callback:(WBActionRequestCallback)callback {
    NSDictionary *params = @{
        @"id" : @(vappId)
    };
    [self requestActionRequestInterfaceWithURI:uri params:params callback:callback];
}

- (void)requestLaunchVappWithVapp:(WBVAppModel *)vapp callback:(WBActionRequestCallback)callback {
    NSDictionary *params = @{
        @"id" : @(vapp.vid),
        @"bgmode" : @(vapp.userInfo.backgroundMode), // background mode set by user
    };
    [self requestActionRequestInterfaceWithURI:@"ar/vapp/launch" params:params callback:callback];
}

- (void)requestLaunchVappWithVappId:(NSInteger)vappId callback:(WBActionRequestCallback)callback {
    [self requestActionRequestInterfaceWithURI:@"ar/vapp/launch" vappId:vappId callback:callback];
}

- (void)requestReserveVappWithVappId:(NSInteger)vappId callback:(WBActionRequestCallback)callback {
    [self requestActionRequestInterfaceWithURI:@"ar/vapp/reserve" vappId:vappId callback:callback];
}

- (void)requestGetVappWithVappId:(NSInteger)vappId callback:(WBActionRequestCallback)callback {
    [self requestActionRequestInterfaceWithURI:@"ar/vapp/get" vappId:vappId callback:callback];
}

- (void)requestReportEventWithType:(WBActionRequestEventType)type callback:(WBActionRequestCallback)callback {
    [self requestReportEventWithType:type data:@{} callback:callback];
}

- (void)requestReportEventWithType:(WBActionRequestEventType)type data:(NSDictionary *)data callback:( WBActionRequestCallback)callback {
    NSDictionary *params = nil;
    if (data && data.count > 0) {
        NSString *jsonData = [data modelToJSONString];
        params = @{
            @"type" : @(type),
            @"data" : jsonData,
        };
    } else {
        params = @{
            @"type" : @(type),
        };
    }
    [self requestActionRequestInterfaceWithURI:@"ar/event" params:params callback:callback];
}

@end

