const NSErrorDomain WBNetworkRequestErrorDomain = @"WBNetworkRequestError";


+ (NSString*)getNetworkErrorMsg:(NSError * _Nullable)error {
    if (error == nil) {
        return @"无错误";
    }
    if ([error.domain compare:WBNetworkRequestErrorDomain] != 0) {
        return @"未知错误";
    } else {
        NSString *errorDesc = [error.userInfo objectForKey:NSLocalizedDescriptionKey];
        if (errorDesc) {
            return errorDesc;
        } else {
            return @"未知错误代码";
        }
    }
}

- (instancetype)initWithBaseURL:(NSURL *)baseURL configuration:(NSURLSessionConfiguration *)configuration delegateQueue:(NSOperationQueue *)delegateQueue {
    if (self = [super init]) {
        _session = [NSURLSession sessionWithConfiguration:configuration delegate:self delegateQueue:delegateQueue];
        _baseURL = baseURL;
    }
    return self;
}

- (instancetype)initWithBaseURL:(NSURL *)baseURL {
    NSURLSessionConfiguration *defaultConfiguration = [NSURLSessionConfiguration defaultSessionConfiguration];
    NSOperationQueue *defaultQueue = [NSOperationQueue mainQueue];
    return [self initWithBaseURL:baseURL configuration:defaultConfiguration delegateQueue:defaultQueue];
}

+ (instancetype)defaultManager {
    static __kindof WBNetworkBaseManager *defaultManager;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSURL *baseURL = [NSURL URLWithString:ABBridge_GetAppBaseURL()];
        defaultManager = [[self alloc] initWithBaseURL:baseURL];
    });
    return defaultManager;
}


