- (void)multipartRequest:(NSString *)URL params:(NSDictionary *)params callback:(WBNetworkBaseCallback)callback {
    NSURLRequest *request = [self createMultipartRequestWithURL:URL params:params];
    [[self.session dataTaskWithRequest:request completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
        [self checkoutWithResponse:response bodyData:data error:error callback:callback];
    }] resume];
}

