#import "WBLinkActionModel.h"
#import "WBRouteManager.h"

@implementation WBLinkActionModel

- (void)executeWithDefaultHandler:(nullable WBActionRequestDefaultHandler)defaultHandler {
    NSURL *url = [NSURL URLWithString:self.link];
    NSParameterAssert(url != nil);
    if (self.type == WBLinkActionTypeWBRoute) {
        WBRouteManager *routeManager = [WBRouteManager sharedManager];
        if (defaultHandler) {
            routeManager.stashedDefaultHandler = ^{
                defaultHandler(self);
            };
        }
        [routeManager performRoute:url sourceInterface:self.sourceInterface];
    } else if (self.type == WBLinkActionTypeDefault) {
        if (defaultHandler) defaultHandler(self);
    } else {
        @try {
            [[UIApplication sharedApplication] openURL:url options:@{} completionHandler:nil];
        } @catch (NSException *exception) {
            NSLog(@"%@", exception);
        }
    }
}

@end

