- (void)showPopupForStyle:(NSNumber *)style withUserInfo:(NSDictionary *)popupInfo {
    if ([style intValue] == 0 || [style intValue] == 1) {
        WBNoticeModel *richMes = [[WBNoticeModel alloc] initWithDict:popupInfo sourceInterface:self.sourceInterface];
        WBPopupManager *popupManager = [WBPopupManager sharedManager];
        if (self.stashedDefaultHandler) {
            popupManager.stashedDefaultHandler = self.stashedDefaultHandler;
            self.stashedDefaultHandler = nil;
        }
        [popupManager initPopups:@[richMes]];
        [popupManager showPopup];
        [popupManager setStashedDefaultHandler:nil]; // 清理可能的循环引用
    } else if ([style intValue] == 2) {
        NSString *resourceUrlString = popupInfo[@"rich_message"][@"image"];
        if ([resourceUrlString hasSuffix:@".zip"]) {    // 如果资源是压缩包
            WBDynamicPopupResUnzip *dynamicPopManager = [WBDynamicPopupResUnzip sharedManager];
            [dynamicPopManager presentPopupWithZipUrl:resourceUrlString popupInfo:popupInfo];
        } else if([resourceUrlString hasSuffix:@".png"] ||
                  [resourceUrlString hasSuffix:@".jpg"] ||
                  [resourceUrlString hasSuffix:@".jpeg"] ||
                  [resourceUrlString hasSuffix:@".webp"]) {    // 如果资源是图片
            WBCustomPopupManager *customPopupManager = [WBCustomPopupManager sharedManager];
            if (self.stashedDefaultHandler) {
                customPopupManager.stashedDefaultHandler = self.stashedDefaultHandler;
                self.stashedDefaultHandler = nil;
            }
            [customPopupManager showCustomPopupWithUserInfo:popupInfo];
            [customPopupManager setStashedDefaultHandler:nil]; // 清理可能的循环引用
        } else {    // 如果 image字段为空
            WBDynamicPopupResUnzip *dynamicPopManager = [WBDynamicPopupResUnzip sharedManager];
            [dynamicPopManager loadResourcesFromUnzippedArchive:@"" popupInfo:popupInfo];
        }
    }
}

- (void)showNextPopupFromQueue:(NSMutableArray<NSDictionary *> *)popupQueue {
    if (self.popupQueue.count > 0) {
        NSDictionary *popupInfo = popupQueue.firstObject;
        NSNumber *style = popupInfo[@"rich_message"][@"style"];
        [self showPopupForStyle:style withUserInfo:popupInfo];
    }
}

- (void)handlePopupQueueLeft {
    if ([self.popupQueueLeft count] > 0) {
        [self showNextPopupFromQueue:self.popupQueueLeft];
        [self.popupQueueLeft removeObjectAtIndex:0];
    }
}

- (void)handlePopupDismissal {
    UIViewController *currentVC = [WBAppManager getUIApplicationCurrentViewController];

    if ([self.popupQueue count] > 0) {
        [self.popupQueue removeObjectAtIndex:0];
        if ([self.popupQueue count] > 0) {
            if ([currentVC isEqual:self.originVC]) {
                [self showNextPopupFromQueue:self.popupQueue];
            } else {
                self.popupQueueLeft = self.popupQueue;
                self.popupQueue = nil;
            }
        }
    }
}

- (void)handleRichMessages:(NSDictionary *)richMessagesData {
    id richMessagesObject = nil; // 初始化 richMessagesObject

    if (richMessagesData[@"rich_message"]) {    // 如果里面是rich_message
        richMessagesObject = richMessagesData[@"rich_message"];
    } else if (richMessagesData[@"rich_messages"]) {    // 如果里面是rich_messages
        richMessagesObject = richMessagesData[@"rich_messages"];

        self.originVC = [WBAppManager getUIApplicationCurrentViewController];    // 获取调用弹窗的原始视图控制器
    }

    if (!richMessagesObject) {
        // 如果 richMessagesObject 为空，则不进行任何处理
        return;
    }
    // 检查 richMessagesObject 是否为非空数组
    if ([richMessagesObject isKindOfClass:[NSArray class]]) {
        NSArray *array = (NSArray *)richMessagesObject;
        if (array.count == 0 || ([array.firstObject isKindOfClass:[NSDictionary class]] && ((NSDictionary *)[array firstObject]).count == 0)) {
            // 如果数组为空或第一个元素是空字典，则不进行任何处理
            return;
        }
    }

    if ([richMessagesObject isKindOfClass:[NSArray class]]) {
        // 如果 rich_messages 是数组，遍历并处理每个元素
        NSArray *richMessagesArray = richMessagesObject;
        if (!self.popupQueue) {
            self.popupQueue = [NSMutableArray array];
        }

        // 使用 for 循环将所有弹窗信息加入队列
        for (NSDictionary *richMessage in richMessagesArray) {
            // 将每个 richMessage 封装在 "rich_message" 的外壳字典中
            NSDictionary *wrappedRichMessage = @{@"rich_message": richMessage};
            [self.popupQueue addObject:wrappedRichMessage];
        }

        // 显示队列中的第一个弹窗
        if ([self.popupQueue count] > 0) {
            [self showNextPopupFromQueue:self.popupQueue];
        }
    } else {
        // 如果 rich_message 不是数组，直接处理字典
        NSNumber *style = richMessagesObject[@"style"];
        [self showPopupForStyle:style withUserInfo:richMessagesData];
    }
}


#pragma mark - 处理ProductIdList

// 将 ProductIdList 转换为 NSNumber 数组
- (NSArray<NSNumber *> *)handleProductIdList:(NSString *)input {
    if (input.length == 0) {
        NSLog(@"productIdList为空");
        return nil;
    }
    NSMutableArray<NSNumber *> *productIDs = [NSMutableArray array];
    NSCharacterSet *whitespaceSet = [NSCharacterSet whitespaceCharacterSet];

    // 去空格 + 数字校验
    [[input componentsSeparatedByString:@","] enumerateObjectsUsingBlock:^(NSString *str, NSUInteger idx, BOOL *stop) {
        NSString *trimmedStr = [str stringByTrimmingCharactersInSet:whitespaceSet];
        if (trimmedStr.length == 0) return;

        NSScanner *scanner = [NSScanner scannerWithString:trimmedStr];
        NSInteger value;
        if ([scanner scanInteger:&value] && scanner.isAtEnd) {
            [productIDs addObject:@(value)];
        }
    }];

    return (productIDs.count > 0) ? [productIDs copy] : nil;
}


