+ (NSArray *)modelsWithDicts:(NSArray<NSDictionary *> *)arrayDict sourceInterface:(nullable NSString *)sourceInterface {
    NSMutableArray *arrayModel = [NSMutableArray arrayWithCapacity:arrayDict.count];
    for (NSDictionary *dict in arrayDict) {
        WBRichMessageModel *model = [[self alloc] initWithDict:dict sourceInterface:sourceInterface];
        [arrayModel addObject:model];
    }
    return arrayModel;
}

- (void)addOperation:(WBRichMessageLinkType)type style:(WBRichMessageLinkStyle)style label:(NSString *)label link:(NSString * _Nullable)link block:(WBActionBlock _Nullable)block {
    if (_operations == nil) {
        _operations = [NSMutableArray array];
    }
    WBRichMessageLinkModel *operation = [[WBRichMessageLinkModel alloc] init];
    operation.type = type;
    operation.style = style;
    operation.label = label;
    operation.link = link;
    operation.postAction = block;
    [self.operations addObject:operation];
}

