+ (instancetype)sharedManager {
    static WBGroMoreAdManager *instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBGroMoreAdManager alloc] init];
        [instance loadStatus]; // 加载保存的状态
        if ([NSThread isMainThread]) {
            instance.vappLaunchVC = [[WBVappLaunchViewController alloc] init];
        } else {
            dispatch_sync(dispatch_get_main_queue(), ^{
                instance.vappLaunchVC = [[WBVappLaunchViewController alloc] init];
            });
        }
        instance.maxNativeAdRetryCount = 3;
        instance.nativeAdRetryInterval = 1.0;     // 初始重试间隔
        instance.nativeAdRetryCount = 0;
    });
    return instance;
}

// 清理预加载的广告
- (void)cleanupPreloadedAdResources {
    // 移除并清理 Banner 广告视图
    if (self.bannerAdView) {
        [self.bannerAdView removeFromSuperview];
        self.bannerAdView.delegate = nil;
        self.bannerAdView = nil;
        self.isBannerAdPreLoaded = NO;
    }

    // 清理信息流广告
    for (BUNativeAd *nativeAd in self.nativeAdDataArray) {
        if (nativeAd.mediation.canvasView) {
            [nativeAd.mediation.canvasView removeFromSuperview];
        }
        nativeAd.delegate = nil;
    }
    self.nativeAdDataArray = nil;

    // 销毁广告管理器
    if (self.nativeAdManager) {
        [self.nativeAdManager.mediation destory]; // 销毁聚合层资源
        self.nativeAdManager.delegate = nil;
        self.nativeAdManager = nil; // 释放管理器
    }

    // 停止并清理重试定时器
    if (self.nativeAdRetryTimer) {
        [self.nativeAdRetryTimer invalidate];
        self.nativeAdRetryTimer = nil;
    }
    self.nativeAdRetryCount = 0;

    // 清理插屏广告（如果正在显示）
    [self closePresentingInterstitialAd];
}


