#pragma mark - GroMore AdSDKInit

- (void)asyncInitializeIfPossibleAndNeeded {
    /******************** 初始化穿山甲聚合SDK ********************/
    BUAdSDKConfiguration *configuration = [BUAdSDKConfiguration configuration];
    // 设置APPID
    configuration.appID = [WBSettingManager sharedManager].ADSAppId;
    // 设置日志输出
    configuration.debugLog = @(0);
    // 设置使用聚合
    configuration.useMediation = YES;
    // 隐私合规配置
    // 是否禁止IDFA
    configuration.mediation.forbiddenIDFA = @(0);
    // 是否限制个性化广告
    configuration.mediation.limitPersonalAds = @(0);
    // 是否限制程序化广告
    configuration.mediation.limitProgrammaticAds = @(0);
    // 主题模式
    configuration.themeStatus = @(BUAdSDKThemeStatus_Normal);


    // disable BU crash handler//// not fully disabled
    Class buCrashHandleClass = objc_getClass("HeimdallrBUEmbed");
    Method m = class_getClassMethod(buCrashHandleClass, sel_getUid("start"));
    method_setImplementation(m, (IMP)myStart);

    // after hook 'start', uploadSession doesn't work
    Class sessionTrackerClass = objc_getClass("HMDBUEmbedSessionTracker");
    Method uploadSessionMethod = class_getInstanceMethod(sessionTrackerClass, @selector(uploadSession));
    method_setImplementation(uploadSessionMethod, (IMP)myUploadSession);


    // 初始化
    [BUAdSDKManager startWithAsyncCompletionHandler:^(BOOL success, NSError *error) {
        dispatch_async(dispatch_get_main_queue(), ^{
            if (success) {
                self.status = WBAdsInitializeStatusSuccess;
                if ([WBSettingManager sharedManager].splashAdEnableShow) {
                    if (!self.vappMsgTapInAdClose) {
                        [self checkAndLoadSplashAd];   // 加载开屏广告
                    } else {    // vapp消息打开
                        self.vappMsgTapInAdClose = FALSE;
                        // 发送点击vapp消息推送，不展示广告的通知
                        [[NSNotificationCenter defaultCenter] postNotificationName:WBSplashAdCloseNotification object:nil];
                    }
                } else {
                    // 发送不展示开屏广告的通知
                    [[NSNotificationCenter defaultCenter] postNotificationName:WBSplashAdCloseNotification object:nil];
                }
                if (WBSettingManager.sharedManager.bannerAdEnableShow && (WBSettingManager.sharedManager.bannerAdPosition & WBAdsShowPositionVappLaunchPage)) {
                    [self groMoreBannerAdPreLoad];  // 预加载 vapp 启动页 banner 广告
                }
                if (WBSettingManager.sharedManager.nativeAdEnableShow && (WBSettingManager.sharedManager.nativeAdPosition & WBAdsShowPositionVappLaunchPage)) {
                    [self groMoreNativeAdPreLoad];  // 预加载 vapp 启动页信息流广告
                }
            } else {
                self.status = WBAdsInitializeStatusError;
                // 发送广告SDK初始化失败的通知
                [[NSNotificationCenter defaultCenter] postNotificationName:WBSplashAdCloseNotification object:nil];
            }
            [self saveStatus]; // 保存当前状态
            [WBEventManager logAppAdSDKInitEvent:@(self.status).stringValue];
        });
    }];
}

