//    NSLog(@"interstitialAdRelatedData：%@", interstitialAdRelatedData);
    NSString *imageUrl = interstitialAdRelatedData[@"imageUrl"];
    NSString *closeImageUrl = interstitialAdRelatedData[@"closeImageUrl"];
    if (imageUrl && ![imageUrl isEqual:@""] && [self isValidURL:imageUrl]) {
        self.hasTip = YES;

        [self downloadAndSetWithImageURL:imageUrl imageView:self.tipsImageView];
        if (closeImageUrl && ![closeImageUrl isEqual:@""]) {
            [self downloadAndSetWithImageURL:closeImageUrl imageView:self.closeButton];
        } else {
            self.closeButton.image = [UIImage imageNamed:@"退出_icon"];
        }

        self.imageTappedLinkType = interstitialAdRelatedData[@"imageTappedLinkType"];
        self.imageTappedLink = interstitialAdRelatedData[@"imageTappedLink"];
        self.closeTappedLinkType = interstitialAdRelatedData[@"closeTappedLinkType"];
        self.closeTappedLink = interstitialAdRelatedData[@"closeTappedLink"];
    }


    // 为图片添加点击手势
    if (self.imageTappedLink) {
        UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleImageTap:)];
        [self.tipsImageView addGestureRecognizer:tapGesture];
        self.tipsImageView.userInteractionEnabled = YES;
    }

    // 关闭按钮手势
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleCloseTap:)];
    [self.closeButton addGestureRecognizer:tapGesture];
    self.closeButton.userInteractionEnabled = YES;
}


- (BOOL)isValidURL:(NSString *)urlString {
    NSURL *url = [NSURL URLWithString:urlString];
    return url && url.scheme && url.host;
}


