- (void)deliver:(NSURL *)url toFirstRouter:(id<JUNRouter>)firstRouter completion:(void (^)(id<JUNRouter> _Nonnull))completionHandler {

    NSOperationQueue *currentQueue = [NSOperationQueue currentQueue];

