    nativeAdManager.mediation.rootViewController = self.vappLaunchVC;
    nativeAdManager.delegate = self;
    self.nativeAdManager = nativeAdManager;

    [self.nativeAdManager loadAdDataWithCount:1];
}

- (void)showNativeAd:(WBVappLaunchViewController *)viewController {
