                if (model.mediation.canvasView) {
                    [viewController.view addSubview:model.mediation.canvasView];

                    CGFloat adWidth = [UIScreen mainScreen].bounds.size.width;
                    [model.mediation.canvasView mas_makeConstraints:^(MASConstraintMaker *make) {
                        make.centerX.bottom.equalTo(viewController.view);
                        make.width.mas_equalTo(adWidth);
                        make.height.mas_equalTo(adWidth * 0.3);
                    }];
                }
            }
        }
    });
}


