        [WBEventManager logAppAdNativeLoadEvent:@"0"];
        self.nativeAdDataArray = nativeAdDataArray;
        self.nativeAdRetryCount = 0;    // 重置重试计数
        for (BUNativeAd *model in nativeAdDataArray) {
            model.rootViewController = self.vappLaunchVC;
            model.delegate = self.vappLaunchVC;
            if (model.mediation.isExpressAd) {
                [model.mediation render];
            }
        }

        // 清理重试定时器
        if (self.nativeAdRetryTimer) {
            [self.nativeAdRetryTimer invalidate];
            self.nativeAdRetryTimer = nil;
        }
    });
}

// 广告加载失败
- (void)nativeAdsManager:(BUNativeAdsManager *)adsManager didFailWithError:(NSError *_Nullable)error {
    dispatch_async(dispatch_get_main_queue(), ^{
        [WBEventManager logAppAdNativeLoadEvent:error.localizedDescription];
        if (self.nativeAdRetryCount < self.maxNativeAdRetryCount) {
            self.nativeAdRetryCount++;

            NSTimeInterval retryInterval = self.nativeAdRetryInterval * pow(2, self.nativeAdRetryCount - 1);
            retryInterval = MIN(retryInterval, 10.0);   // 限制最大间隔为10秒

            if (self.nativeAdRetryTimer) {
                [self.nativeAdRetryTimer invalidate];
                self.nativeAdRetryTimer = nil;
            }
            self.nativeAdRetryTimer = [NSTimer scheduledTimerWithTimeInterval:retryInterval
                                                                      target:self
                                                                    selector:@selector(retryNativeAdLoad)
                                                                    userInfo:nil
                                                                     repeats:NO];
            [[NSRunLoop mainRunLoop] addTimer:self.nativeAdRetryTimer forMode:NSRunLoopCommonModes];
        } else {
            self.nativeAdRetryCount = 0;
            if (self.nativeAdRetryTimer) {
                [self.nativeAdRetryTimer invalidate];
                self.nativeAdRetryTimer = nil;
            }
        }
    });
}

