- (void)handleLinkWithType:(NSString *)linkType link:(NSString *)link {
    // 判断 link 是否有效
    if (link && ![link isEqualToString:@""]) {
        if ([linkType integerValue] == linkType_UrlScheme) {
            NSURL *url = [NSURL URLWithString:link];
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [[WBRouteManager sharedManager] performRoute:url sourceInterface:@"action/interstitialAd"];  // 路由跳转
            });
        } else if ([linkType integerValue] == linkType_Safari) {
            [UIApplication.sharedApplication openURL:[NSURL URLWithString:link] options:@{} completionHandler:nil]; // 浏览器跳转
        } else if ([linkType integerValue] == linkType_WebView) {
            WBWebViewManager *webVC = [[WBWebViewManager alloc] initWithURL:[NSURL URLWithString:link]];
            webVC.modalPresentationStyle = UIModalPresentationFullScreen;
            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
            [self dismissViewControllerAnimated:false completion:^{
                [rootVC presentViewController:webVC animated:true completion:nil];
            }];
            webVC.webVC.dismissBlock = ^{
                [rootVC dismissViewControllerAnimated:YES completion:nil];
            };
        } else {
            NSLog(@"这是一个暂时无法识别的link类型");
        }
    }
}

- (void)downloadAndSetWithImageURL:(NSString *)imageUrl imageView:(UIImageView *)imageView {
    NSURL *url = [NSURL URLWithString:imageUrl];

    // 异步下载图片
    NSURLSession *session = [NSURLSession sharedSession];
    NSURLSessionDataTask *downloadTask = [session dataTaskWithURL:url completionHandler:^(NSData *data, NSURLResponse *response, NSError *error) {
        if (error) {
            // 下载失败
            NSLog(@"图片下载失败: %@", error.localizedDescription);
            return;
        }

        if (data) {
            // 下载成功，更新 UI
            UIImage *image = [UIImage imageWithData:data];
            dispatch_async(dispatch_get_main_queue(), ^{
                [imageView setImage:image];
                [WBGroMoreAdManager sharedManager].isInterstitialAdLocked = TRUE;
            });
        }
    }];
    [downloadTask resume];
}


