lelele，我准备改成这两块，先给你看代码，不动仓库。

先改 [WBAppManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/WBAppManager.m)，把 rootVC 改成优先取当前前台 `keyWindow`，别再直接拿 `scene.windows.firstObject`：

```objc
+ (UIWindow*)getUIApplicationKeywindow {
    UIWindow *keyWindow = UIApplication.sharedApplication.keyWindow;
    if (keyWindow) {
        return keyWindow;
    }

    if (@available(iOS 13.0, *)) {
        for (UIScene *scene in UIApplication.sharedApplication.connectedScenes) {
            if (![scene isKindOfClass:[UIWindowScene class]]) {
                continue;
            }

            UIWindowScene *windowScene = (UIWindowScene *)scene;
            if (windowScene.activationState != UISceneActivationStateForegroundActive) {
                continue;
            }

            for (UIWindow *window in windowScene.windows) {
                if (window.isKeyWindow) {
                    return window;
                }
            }

            for (UIWindow *window in windowScene.windows) {
                if (!window.hidden && window.alpha > 0.0 && window.windowLevel == UIWindowLevelNormal) {
                    return window;
                }
            }

            if (windowScene.windows.firstObject) {
                return windowScene.windows.firstObject;
            }
        }
    }

    return UIApplication.sharedApplication.windows.firstObject;
}

+ (UIViewController *)getUIApplicationRootViewController {
    return [self getUIApplicationKeywindow].rootViewController;
}
```

再改 [WBGroMoreAdManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/Ads/GroMore/WBGroMoreAdManager.m)，核心是两件事：
1. 用当前可见 VC 来 `present`
2. 等 `present` 完成后再 `loadNativeExpressAd`，避开还没挂上去就 `showAd` 的竞态

```objc
- (void)checkAndLoadInterstitialAd:(NSDictionary *)interstitialAdRelatedData {
    dispatch_async(dispatch_get_main_queue(), ^{
        if (self.hasPresentingScreenAd) {
            return;
        }
        if (self.status != WBAdsInitializeStatusSuccess) {
            return;
        }

        UIViewController *controller = [WBAppManager getUIApplicationCurrentViewController];
        if (!controller) {
            controller = [WBAppManager getUIApplicationRootViewController];
        }
        while (controller.presentedViewController) {
            controller = controller.presentedViewController;
        }
        if (!controller) {
            return;
        }

        self.hasPresentingScreenAd = TRUE;

        if (!self.interstitialAdVC) {
            self.interstitialAdVC = [[WBGroInterstitialAdViewController alloc] init];
        }

        self.interstitialAdVC.modalPresentationStyle = UIModalPresentationOverFullScreen;

        __weak typeof(self) weakSelf = self;
        [controller presentViewController:self.interstitialAdVC animated:YES completion:^{
            [weakSelf.interstitialAdVC loadNativeExpressAd:interstitialAdRelatedData];
        }];
    });
}
```

我这里顺手还改了一个小坑：原来 `status` 还没成功时，`hasPresentingScreenAd` 也会被置成 `TRUE`，这个状态容易卡死，后面占屏广告都进不来。上面这版一起避掉了。

如果你看这版方向没问题，我再正式帮你落到代码里。

