payload.message:
lelele，可以，而且我建议你现在别再跟断点死磕了，直接上日志，这个场景更稳。

我的建议是：**不要打 `%@` 整个对象**，尽量打印这几类信息就够了：

- 指针地址 `%p`
- 类名 `NSStringFromClass(obj.class)`
- `presentedViewController`
- `presentingViewController`
- `view.window`
- `isKeyWindow`
- `windowLevel`

这样基本能把“当前最上层是谁、挂在哪扇窗、有没有真正 present 上去”都看出来。

你可以先这么加，我按“最少改动、信息最全”给你一版。

先在 [WBGroMoreAdManager.m](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/Ads/GroMore/WBGroMoreAdManager.m) 顶部加两个小工具方法：

```objc
static NSString *WBClassName(id obj) {
    return obj ? NSStringFromClass([obj class]) : @"nil";
}

static void WBLogVC(NSString *tag, UIViewController *vc) {
    UIWindow *window = vc.view.window;
    NSLog(@"[Interstitial][%@] vc=%p class=%@ presented=%p(%@) presenting=%p(%@) window=%p key=%d hidden=%d level=%.1f",
          tag,
          vc,
          WBClassName(vc),
          vc.presentedViewController,
          WBClassName(vc.presentedViewController),
          vc.presentingViewController,
          WBClassName(vc.presentingViewController),
          window,
          window.isKeyWindow,
          window.hidden,
          window.windowLevel);
}
```

然后把 [`checkAndLoadInterstitialAd:`](/Users/liuyifu/Documents/Bface/weihe/WeBox/WeBox/Core/Service/Ads/GroMore/WBGroMoreAdManager.m#L203) 改成先打一整串链路日志：

```objc
- (void)checkAndLoadInterstitialAd:(NSDictionary *)interstitialAdRelatedData {
    dispatch_async(dispatch_get_main_queue(), ^{
        NSLog(@"[Interstitial][enter] hasPresentingScreenAd=%d status=%ld data=%@",
              self.hasPresentingScreenAd,
              (long)self.status,
              interstitialAdRelatedData);

        if (self.hasPresentingScreenAd) {
            NSLog(@"[Interstitial][return] blocked by hasPresentingScreenAd");
            return;
        } else {
            self.hasPresentingScreenAd = TRUE;
        }

        if (self.status == WBAdsInitializeStatusSuccess) {
            if (!self.interstitialAdVC) {
                self.interstitialAdVC = [[WBGroInterstitialAdViewController alloc] init];
                NSLog(@"[Interstitial][vc] create interstitialAdVC=%p class=%@",
                      self.interstitialAdVC,
                      WBClassName(self.interstitialAdVC));
            } else {
                NSLog(@"[Interstitial][vc] reuse interstitialAdVC=%p class=%@",
                      self.interstitialAdVC,
                      WBClassName(self.interstitialAdVC));
            }

            self.interstitialAdVC.modalPresentationStyle = UIModalPresentationOverCurrentContext;
            [self.interstitialAdVC loadNativeExpressAd:interstitialAdRelatedData];

            UIViewController *controller = [WBAppManager getUIApplicationRootViewController];
            WBLogVC(@"root", controller);

            NSInteger depth = 0;
            while (controller.presentedViewController) {
                depth++;
                controller = controller.presentedViewController;
                WBLogVC([NSString stringWithFormat:@"presented-%ld", (long)depth], controller);
            }

            WBLogVC(@"final-presenter", controller);
            WBLogVC(@"interstitial-before-present", self.interstitialAdVC);

            if (controller && self.interstitialAdVC) {
                NSLog(@"[Interstitial][present] begin presenter=%p(%@) target=%p(%@)",
                      controller,
                      WBClassName(controller),
                      self.interstitialAdVC,
                      WBClassName(self.interstitialAdVC));

                [controller presentViewController:self.interstitialAdVC animated:YES completion:^{
                    NSLog(@"[Interstitial][present] completion presenter=%p(%@) target=%p(%@)",
                          controller,
